//#region src/lib/pdf-utils.ts
async function getLogoBase64(userDetails) {
	if (!userDetails?.imobiliaria_logo || !userDetails?.collectionId || !userDetails?.id) return null;
	try {
		const logoUrl = pb.files.getURL(userDetails, userDetails.imobiliaria_logo);
		const blob = await (await fetch(logoUrl)).blob();
		return new Promise((resolve) => {
			const reader = new FileReader();
			reader.onloadend = () => resolve(reader.result);
			reader.readAsDataURL(blob);
		});
	} catch (e) {
		console.error("Failed to load logo", e);
		return null;
	}
}
