var logSystemError = async (data) => {
	try {
		const payload = {
			...data,
			user: data.user || (pb.authStore.isValid ? pb.authStore.model?.id : void 0),
			route: data.route || window.location.pathname
		};
		await pb.collection("system_error_logs").create(payload);
	} catch (err) {
		console.error("Failed to log system error:", err);
	}
};
var getSystemErrorLogs = async (page = 1, perPage = 50, filter = "") => {
	return pb.collection("system_error_logs").getList(page, perPage, {
		sort: "-created",
		filter,
		expand: "user"
	});
};
