//#region src/services/users.ts
var updateUserProfile = async (id, data) => {
	const record = await pb.send(`/api/collections/users/records/${id}`, {
		method: "PATCH",
		body: JSON.stringify(data),
		headers: { "Content-Type": "application/json" }
	});
	if (pb.authStore.record?.id === id) await pb.collection("users").authRefresh();
	return record;
};
