async function getKnowledgeAuditLogs(knowledgeItemId) {
	const filter = knowledgeItemId ? `knowledge_item = "${knowledgeItemId}"` : "";
	return await pb.collection("knowledge_audit_logs").getFullList({
		sort: "-created",
		filter,
		expand: "user,knowledge_item"
	});
}
